**Async/Await vs Callback Pattern:**

```javascript
// Callback with next(err)
function syncSearchIndex(query, callback) {
  try {
    const results = performSearch(query);
    callback(null, results);
  } catch (error) {
    callback(error);
  }
}

// Async/await equivalent
async function asyncSearchIndex(query) {
  return performSearch(query); // Throws on error
}
```

